class SecureLogger {
  final bool enabled;

  const SecureLogger(this.enabled);

  void info(String message, [Map<String, Object?>? context]) {
    if (!enabled) return;
    debugPrint('[Payment][INFO] $message ${_sanitize(context)}');
  }

  void warn(String message, [Map<String, Object?>? context]) {
    if (!enabled) return;
    debugPrint('[Payment][WARN] $message ${_sanitize(context)}');
  }

  void error(String message, [Map<String, Object?>? context]) {
    if (!enabled) return;
    debugPrint('[Payment][ERROR] $message ${_sanitize(context)}');
  }

  String _sanitize(Map<String, Object?>? context) {
    if (context == null || context.isEmpty) return '';
    final sanitized = <String, Object?>{};
    context.forEach((key, value) {
      final lower = key.toLowerCase();
      if (lower.contains('token') ||
          lower.contains('secret') ||
          lower.contains('card') ||
          lower.contains('receipt') ||
          lower.contains('signature')) {
        sanitized[key] = '***';
      } else {
        sanitized[key] = value;
      }
    });
    return jsonEncode(sanitized);
  }
}

class PaymentSecurity {
  static String generateIdempotencyKey({
    required String orderId,
    required String customerId,
    required int amountMinor,
    required String currency,
  }) {
    final seed = '$orderId|$customerId|$amountMinor|$currency|${DateTime.now().toUtc().millisecondsSinceEpoch}';
    return sha256.convert(utf8.encode(seed)).toString();
  }

  static void validateNoRawCardData(Map<String, dynamic> payload) {
    final encoded = jsonEncode(payload).toLowerCase();
    const banned = [
      'cardnumber',
      'pan',
      'cvv',
      'cvc',
      'exp_month',
      'exp_year',
      'expiry',
      'track2',
    ];
    for (final item in banned) {
      if (encoded.contains(item)) {
        throw const PaymentException(
          'pci_violation',
          'Raw cardholder data detected. Use tokenized payment methods only.',
        );
      }
    }
  }
}

class PaymentHttpClient {
  final PaymentConfig config;
  final http.Client _client;
  final SecureLogger _logger;

  PaymentHttpClient({
    required this.config,
    http.Client? client,
  })  : _client = client ?? http.Client(),
        _logger = SecureLogger(config.enableLogging);

  Future<Map<String, dynamic>> post(
    String path, {
    required Map<String, dynamic> body,
    Map<String, String>? headers,
  }) async {
    PaymentSecurity.validateNoRawCardData(body);
    final uri = config.backendBaseUrl.resolve(path);
    final mergedHeaders = <String, String>{
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'X-Api-Version': config.apiVersion,
      ...config.defaultHeaders,
      ...?headers,
    };

    _logger.info('POST $path', {'body': body});

    final response = await _client
        .post(
          uri,
          headers: mergedHeaders,
          body: jsonEncode(body),
        )
        .timeout(config.networkTimeout);

    return _handleResponse(response);
  }

  Future<Map<String, dynamic>> get(
    String path, {
    Map<String, String>? headers,
  }) async {
    final uri = config.backendBaseUrl.resolve(path);
    final mergedHeaders = <String, String>{
      'Accept': 'application/json',
      'X-Api-Version': config.apiVersion,
      ...config.defaultHeaders,
      ...?headers,
    };

    _logger.info('GET $path');

    final response = await _client
        .get(
          uri,
          headers: mergedHeaders,
        )
        .timeout(config.networkTimeout);

    return _handleResponse(response);
  }

  Map<String, dynamic> _handleResponse(http.Response response) {
    final body = response.body.isEmpty
        ? <String, dynamic>{}
        : (jsonDecode(response.body) as Map<String, dynamic>);

    if (response.statusCode >= 200 && response.statusCode < 300) {
      return body;
    }

    throw PaymentException(
      'http_${response.statusCode}',
      (body['message'] ?? 'Payment service request failed') as String,
      body,
    );
  }

  void dispose() {
    _client.close();
  }
}

class MobileWalletBridge {
  static const MethodChannel _channel = MethodChannel('payment_module/wallet');

  Future<bool> isApplePaySupported() async {
    if (!Platform.isIOS) return false;
    final result = await _channel.invokeMethod<bool>('isApplePaySupported');
    return result ?? false;
  }

  Future<bool> isGooglePaySupported() async {
    if (!Platform.isAndroid) return false;
    final result = await _channel.invokeMethod<bool>('isGooglePaySupported');
    return result ?? false;
  }

  Future<String> presentApplePaySheet({
    required PaymentConfig config,
    required WalletPaymentRequest request,
  }) async {
    final token = await _channel.invokeMethod<String>(
      'presentApplePaySheet',
      {
        'merchantIdentifier': config.merchantIdentifier,
        'publishableKey': config.publishableKey,
        'environment': config.environment.name,
        'request': request.toJson(),
      },
    );
    if (token == null || token.isEmpty) {
      throw const PaymentException('wallet_cancelled', 'Apple Pay was cancelled.');
    }
    return token;
  }

  Future<String> presentGooglePaySheet({
    required PaymentConfig config,
    required WalletPaymentRequest request,
  }) async {
    final token = await _channel.invokeMethod<String>(
      'presentGooglePaySheet',
      {
        'merchantIdentifier': config.merchantIdentifier,
        'publishableKey': config.publishableKey,
        'environment': config.environment.name,
        'request': request.toJson(),
      },
    );
    if (token == null || token.isEmpty) {
      throw const PaymentException('wallet_cancelled', 'Google Pay was cancelled.');
    }
    return token;
  }
}

class InAppPurchaseService {
  final PaymentConfig config;
  final PaymentHttpClient _http;
  final InAppPurchase _iap = InAppPurchase.instance;
  final SecureLogger _logger;
  StreamSubscription<List<PurchaseDetails>>? _purchaseSubscription;

  InAppPurchaseService(this.config, this._http)
      : _logger = SecureLogger(config.enableLogging);

  Future<bool> isAvailable() => _iap.isAvailable();

  Future<ProductDetailsResponse> queryProducts() {
    return _iap.queryProductDetails(config.iapProductIds.toSet());
  }

  void startPurchaseListener({
    required Future<void> Function(PurchaseVerificationResult verification) onVerified,
    required Future<void> Function(PurchaseDetails purchase, Object error) onError,
  }) {
    _purchaseSubscription?.cancel();
    _purchaseSubscription = _iap.purchaseStream.listen(
      (purchases) async {
        for (final purchase in purchases) {
          try {
            await _handlePurchaseUpdate(purchase, onVerified);
          } catch (e) {
            await onError(purchase, e);
          }
        }
      },
      onError: (error) {
        _logger.error('IAP stream error', {'error': error.toString()});
      },
      cancelOnError: false,
    );
  }

  Future<void> buyConsumable(ProductDetails product) async {
    final param = PurchaseParam(productDetails: product);
    final started = await _iap.buyConsumable(purchaseParam: param, autoConsume: true);
    if (!started) {
      throw const PaymentException('iap_start_failed', 'Unable to start consumable purchase.');
    }
  }

  Future<void> buyNonConsumable(ProductDetails product) async {
    final param = PurchaseParam(productDetails: product);
    final started = await _iap.buyNonConsumable(purchaseParam: param);
    if (!started) {
      throw const PaymentException('iap_start_failed', 'Unable to start non-consumable purchase.');
    }
  }

  Future<void> restorePurchases() => _iap.restorePurchases();

  Future<void> _handlePurchaseUpdate(
    PurchaseDetails purchase,
    Future<void> Function(PurchaseVerificationResult verification) onVerified,
  ) async {
    _logger.info('IAP update', {
      'productId': purchase.productID,
      'status': purchase.status.name,
    });

    if (purchase.status == PurchaseStatus.pending) {
      return;
    }

    if (purchase.status == PurchaseStatus.error) {
      throw PaymentException(
        'iap_error',
        purchase.error?.message ?? 'In-app purchase failed.',
        purchase.error,
      );
    }

    if (purchase.status == PurchaseStatus.purchased ||
        purchase.status == PurchaseStatus.restored) {
      final verification = await verifyPurchase(purchase);
      if (!verification.valid) {
        throw const PaymentException('iap_verification_failed', 'Purchase verification failed.');
      }

      await onVerified(verification);

      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    }

    if (purchase.status == PurchaseStatus.canceled) {
      throw const PaymentException('iap_cancelled', 'User cancelled the purchase.');
    }
  }

  Future<PurchaseVerificationResult> verifyPurchase(PurchaseDetails purchase) async {
    final body = {
      'platform': Platform.isIOS ? 'ios' : Platform.isAndroid ? 'android' : 'unknown',
      'productId': purchase.productID,
      'purchaseId': purchase.purchaseID,
      'transactionDate': purchase.transactionDate,
      'verificationData': {
        'serverVerificationData': purchase.verificationData.serverVerificationData,
        'source': purchase.verificationData.source,
      },
    };

    final json = await _http.post(
      '/payments/iap/verify',
      body: body,
      headers: {
        'X-Verification-Only': 'true',
      },
    );

    return PurchaseVerificationResult.fromJson(json);
  }

  Future<void> dispose() async {
    await _purchaseSubscription?.cancel();
  }
}

class PaymentGatewayService {
  final PaymentConfig config;
  final PaymentHttpClient _http;
  final SecureLogger _logger;

  PaymentGatewayService(this.config, this._http)
      : _logger = SecureLogger(config.enableLogging);

  Future<PaymentResult> createAndProcessPayment(PaymentRequest request) async {
    final idempotencyKey = request.idempotencyKey ??
        PaymentSecurity.generateIdempotencyKey(
          orderId: request.orderId,
          customerId: request.customer.id,
          amountMinor: request.amount.amountMinor,
          currency: request.amount.currency,
        );

    final payload = {
      ...request.toJson(),
      'idempotencyKey': idempotencyKey,
      'platform': _platformName(),
      'environment': config.environment.name,
    };

    final json = await _http.post(
      '/payments/transactions',
      body: payload,
      headers: {
        'Idempotency-Key': idempotencyKey,
      },
    );

    final result = PaymentResult.fromJson(json);
    _logger.info('Payment processed', {
      'transactionId': result.transactionId,
      'status': result.status.name,
    });
    return result;
  }

  Future<PaymentResult> capturePayment(String transactionId, {int? amountMinor}) async {
    final json = await _http.post(
      '/payments/transactions/$transactionId/capture',
      body: {
        if (amountMinor != null) 'amountMinor': amountMinor,
      },
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> refundPayment(String transactionId, {int? amountMinor, String? reason}) async {
    final json = await _http.post(
      '/payments/transactions/$transactionId/refund',
      body: {
        if (amountMinor != null) 'amountMinor': amountMinor,
        if (reason != null) 'reason': reason,
      },
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> getTransaction(String transactionId) async {
    final json = await _http.get('/payments/transactions/$transactionId');
    return PaymentResult.fromJson(json);
  }

  String _platformName() {
    if (Platform.isIOS) return PaymentPlatform.ios.name;
    if (Platform.isAndroid) return PaymentPlatform.android.name;
    return PaymentPlatform.unknown.name;
  }
}

class PaymentModule {
  final PaymentConfig config;
  late final PaymentHttpClient _http;
  late final PaymentGatewayService gateway;
  late final InAppPurchaseService inAppPurchases;
  late final MobileWalletBridge walletBridge;
  final SecureLogger _logger;

  PaymentModule._(this.config) : _logger = SecureLogger(config.enableLogging) {
    _http = PaymentHttpClient(config: config);
    gateway = PaymentGatewayService(config, _http);
    inAppPurchases = InAppPurchaseService(config, _http);
    walletBridge = MobileWalletBridge();
  }

  static Future<PaymentModule> initialize(PaymentConfig config) async {
    final module = PaymentModule._(config);
    await module._runStartupChecks();
    return module;
  }

  Future<void> _runStartupChecks() async {
    if (config.publishableKey.isEmpty) {
      throw const PaymentException('config_error', 'Publishable key is required.');
    }
    if (config.merchantIdentifier.isEmpty) {
      throw const PaymentException('config_error', 'Merchant identifier is required.');
    }
    if (!config.backendBaseUrl.hasScheme) {
      throw const PaymentException('config_error', 'Backend base URL must be absolute.');
    }
    if (config.backendBaseUrl.scheme != 'https') {
      throw const PaymentException('security_error', 'HTTPS is required for payment APIs.');
    }

    _logger.info('Payment module initialized', {
      'environment': config.environment.name,
      'backend': config.backendBaseUrl.toString(),
    });
  }

  Future<PaymentResult> processApplePay(WalletPaymentRequest request) async {
    final supported = await walletBridge.isApplePaySupported();
    if (!supported) {
      throw const PaymentException('apple_pay_unavailable', 'Apple Pay is not available on this device.');
    }

    final walletToken = await walletBridge.presentApplePaySheet(
      config: config,
      request: request,
    );

    return gateway.createAndProcessPayment(
      PaymentRequest(
        orderId: request.orderId,
        amount: request.amount,
        customer: request.customer,
        methodType: PaymentMethodType.applePay,
        paymentMethodToken: walletToken,
        metadata: request.metadata,
      ),
    );
  }

  Future<PaymentResult> processGooglePay(WalletPaymentRequest request) async {
    final supported = await walletBridge.isGooglePaySupported();
    if (!supported) {
      throw const PaymentException('google_pay_unavailable', 'Google Pay is not available on this device.');
    }

    final walletToken = await walletBridge.presentGooglePaySheet(
      config: config,
      request: request,
    );

    return gateway.createAndProcessPayment(
      PaymentRequest(
        orderId: request.orderId,
        amount: request.amount,
        customer: request.customer,
        methodType: PaymentMethodType.googlePay,
        paymentMethodToken: walletToken,
        metadata: request.metadata,
      ),
    );
  }

  Future<PaymentResult> processTokenizedCard({
    required String orderId,
    required Money amount,
    required CustomerProfile customer,
    required String paymentMethodToken,
    BillingAddress? billingAddress,
    Map<String, dynamic> metadata = const {},
    bool captureImmediately = true,
  }) {
    return gateway.createAndProcessPayment(
      PaymentRequest(
        orderId: orderId,
        amount: amount,
        customer: customer,
        methodType: PaymentMethodType.cardTokenized,
        paymentMethodToken: paymentMethodToken,
        billingAddress: billingAddress,
        metadata: metadata,
        captureImmediately: captureImmediately,
      ),
    );
  }

  Future<void> dispose() async {
    await inAppPurchases.dispose();
    _http.dispose();
  }
}

class ExamplePaymentFacade {
  final PaymentModule module;

  ExamplePaymentFacade(this.module);

  Future<PaymentResult> checkoutWithWallet({
    required String orderId,
    required int amountMinor,
    required String currency,
    required String label,
    required CustomerProfile customer,
    required String countryCode,
    Map<String, dynamic> metadata = const {},
  }) async {
    final request = WalletPaymentRequest(
      amount: Money(currency: currency, amountMinor: amountMinor),
      countryCode: countryCode,
      label: label,
      orderId: orderId,
      customer: customer,
      metadata: metadata,
    );

    if (Platform.isIOS) {
      return module.processApplePay(request);
    }
    if (Platform.isAndroid) {
      return module.processGooglePay(request);
    }

    throw const PaymentException('unsupported_platform', 'Wallet payments are only supported on iOS and Android.');
  }

  Future<PaymentResult> checkoutWithTokenizedCard({
    required String orderId,
    required int amountMinor,
    required String currency,
    required CustomerProfile customer,
    required String paymentMethodToken,
    BillingAddress? billingAddress,
    Map<String, dynamic> metadata = const {},
  }) {
    return module.processTokenizedCard(
      orderId: orderId,
      amount: Money(currency: currency, amountMinor: amountMinor),
      customer: customer,
      paymentMethodToken: paymentMethodToken,
      billingAddress: billingAddress,
      metadata: metadata,
    );
  }
}